const now = new Date(new Date().toLocaleString('en-US', {timeZone:'Asia/Kolkata'}));
const dd = String(now.getDate()).padStart(2,'0');
const mm = String(now.getMonth()+1).padStart(2,'0');
const yyyy = now.getFullYear();
const today = `${dd}-${mm}-${yyyy}`;
const nowStr = now.toLocaleString('en-IN', {timeZone:'Asia/Kolkata'});
const headers = 'Date,StudentID,Name,Class,Subject,Teacher,Status,AbsencesLast30Days,ConsecutiveStreak,AttendancePct,Trend,AlertLevel,AlertReason,ParentName,EmailSent,WhatsAppSent';
return [{json:{todayRows:[], headers, nowStr, today, allAbsent:[], noAbsencesToday:true}}];

function parseDate(str) {
  const p = String(str||'').trim().split('-');
  if (p.length===3) return new Date(+p[2],+p[1]-1,+p[0]);
  return new Date(0);
}

// Always use Asia/Kolkata timezone for consistent "today" regardless of server TZ
const nowIST = new Date(new Date().toLocaleString('en-US', {timeZone:'Asia/Kolkata'}));
const todayStr = String(nowIST.getDate()).padStart(2,'0')+'-'+String(nowIST.getMonth()+1).padStart(2,'0')+'-'+nowIST.getFullYear();
const todayDate = parseDate(todayStr);
const thirtyAgo = new Date(todayDate); thirtyAgo.setDate(thirtyAgo.getDate()-30);

// Normalize a raw date string — handles DD-MM-YYYY, YYYY-MM-DD, D/M/YYYY etc.
function normalizeDate(raw) {
  const s = String(raw||'').trim();
  // Already DD-MM-YYYY
  if (/^\d{2}-\d{2}-\d{4}$/.test(s)) return s;
  // YYYY-MM-DD (ISO)
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) {
    const [y,m,d] = s.split('-');
    return `${d}-${m}-${y}`;
  }
  // D/M/YYYY or DD/MM/YYYY
  if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(s)) {
    const [d,m,y] = s.split('/');
    return String(d).padStart(2,'0')+'-'+String(m).padStart(2,'0')+'-'+y;
  }
  // Excel serial number (number only) — convert to date
  if (/^\d{5}$/.test(s)) {
    const serial = parseInt(s);
    const excelEpoch = new Date(1899,11,30);
    const date = new Date(excelEpoch.getTime() + serial * 86400000);
    return String(date.getDate()).padStart(2,'0')+'-'+String(date.getMonth()+1).padStart(2,'0')+'-'+date.getFullYear();
  }
  return s;
}

const byStudent = {};
for (const item of $input.all()) {
  const sid = String(item.json.StudentID||'').trim();
  if (!sid) continue;
  // Normalize the date on every row as it comes in
  const normalizedDate = normalizeDate(item.json.Date);
  const enriched = {...item.json, Date: normalizedDate};
  if (!byStudent[sid]) byStudent[sid]=[];
  byStudent[sid].push(enriched);
}

const output = [];
for (const [sid,rows] of Object.entries(byStudent)) {
  const contact = rows[0];
  const last30 = rows.filter(r=>{const d=parseDate(r.Date);return d>=thirtyAgo&&d<=todayDate;}).sort((a,b)=>parseDate(a.Date)-parseDate(b.Date));
  const absent30=last30.filter(r=>String(r.Status).toLowerCase()==='absent').length;
  const total30=last30.length;
  const attendancePct=total30>0?Math.round(((total30-absent30)/total30)*100):100;
  let streak=0;
  for(let i=last30.length-1;i>=0;i--){if(String(last30[i].Status).toLowerCase()==='absent')streak++;else break;}
  const l7=last30.slice(-7),p7=last30.slice(-14,-7);
  const ar=a=>a.length?a.filter(r=>String(r.Status).toLowerCase()==='absent').length/a.length:0;
  const trend=ar(l7)>ar(p7)+0.1?'WORSENING':ar(l7)<ar(p7)-0.1?'IMPROVING':'STABLE';
  let alertLevel='LOW',alertReason=`${absent30} absence(s) in 30 days`;
  if(absent30>=5||streak>=3){alertLevel='HIGH';alertReason=streak>=3?`${streak} consecutive absences`:`${absent30} absences in 30 days`;}
  else if(absent30>=3){alertLevel='MEDIUM';alertReason=`${absent30} absences in 30 days`;}
  const todayRow=rows.find(r=>String(r.Date).trim()===todayStr)||rows[rows.length-1];
  output.push({json:{studentId:sid,name:contact.Name||'Student',parentName:contact.ParentName||'Parent',email:contact.Email||'',phone:contact.Phone||'',class:todayRow.Class||contact.Class||'',subject:todayRow.Subject||'',teacher:todayRow.Teacher||'',date:todayStr,absencesLast30Days:absent30,consecutiveStreak:streak,attendancePct,trend,alertLevel,alertReason}});
}
return output;

const item = $input.item.json;
const cfg = { HIGH:{color:'#dc2626',bg:'#fef2f2',border:'#fecaca',label:'Critical Alert',icon:'🔴'}, MEDIUM:{color:'#d97706',bg:'#fffbeb',border:'#fde68a',label:'Warning',icon:'🟡'}, LOW:{color:'#16a34a',bg:'#f0fdf4',border:'#bbf7d0',label:'Low Risk',icon:'🟢'} }[item.alertLevel]||{color:'#16a34a',bg:'#f0fdf4',border:'#bbf7d0',label:'Low Risk',icon:'🟢'};
const trendIcon={WORSENING:'📈 Worsening',STABLE:'➡️ Stable',IMPROVING:'📉 Improving'};
const subject=`${cfg.icon} Absence: ${item.name} — ${item.date} [${item.alertLevel}]`;
const body=`<html><body style="font-family:Arial,sans-serif;max-width:600px;margin:auto"><div style="background:#f9fafb;border:1px solid #e5e7eb;border-radius:10px;padding:24px"><h2>Absence Notification</h2><p style="color:#6b7280;font-size:13px">${item.date}</p><div style="background:${cfg.bg};border-left:4px solid ${cfg.color};padding:12px;border-radius:4px;margin:16px 0"><strong style="color:${cfg.color}">${cfg.label}: ${item.alertReason}</strong></div><table style="width:100%;font-size:14px;border-collapse:collapse"><tr><td style="padding:8px;color:#6b7280">Student</td><td><b>${item.name}</b></td></tr><tr style="background:#f9f9f9"><td style="padding:8px;color:#6b7280">Class</td><td>${item.class}</td></tr><tr><td style="padding:8px;color:#6b7280">Subject/Teacher</td><td>${item.subject} / ${item.teacher}</td></tr><tr style="background:#f9f9f9"><td style="padding:8px;color:#6b7280">Absences 30d</td><td><b>${item.absencesLast30Days}</b></td></tr><tr><td style="padding:8px;color:#6b7280">Streak</td><td>${item.consecutiveStreak} day(s)</td></tr><tr style="background:#f9f9f9"><td style="padding:8px;color:#6b7280">Attendance</td><td><b>${item.attendancePct}%</b></td></tr><tr><td style="padding:8px;color:#6b7280">Trend</td><td>${trendIcon[item.trend]||item.trend}</td></tr></table><p style="margin-top:16px;font-size:13px;color:#4b5563">Dear ${item.parentName}, please contact the school if you have questions.</p></div></body></html>`;
return [{json:{...item,emailSubject:subject,emailBody:body}}];

const allAbsent=$input.all().map(i=>i.json).filter(i=>i.studentId); // filter out empty items
const now=new Date(new Date().toLocaleString('en-US', {timeZone:'Asia/Kolkata'}));
const dd=String(now.getDate()).padStart(2,'0'),mm=String(now.getMonth()+1).padStart(2,'0'),yyyy=now.getFullYear();
const today=`${dd}-${mm}-${yyyy}`;
const nowStr=now.toLocaleString('en-IN',{timeZone:'Asia/Kolkata'});
const headers='Date,StudentID,Name,Class,Subject,Teacher,Status,AbsencesLast30Days,ConsecutiveStreak,AttendancePct,Trend,AlertLevel,AlertReason,ParentName,EmailSent,WhatsAppSent';

// If no absences today (false branch), todayRows will be empty — dashboard shows "No absences"
const todayRows=allAbsent.map(s=>[today,s.studentId,s.name,s.class,s.subject,s.teacher,'Absent',s.absencesLast30Days,s.consecutiveStreak,s.attendancePct,s.trend,s.alertLevel,`"${s.alertReason}"`,s.parentName,s.email?'YES':'NO',s.phone?'YES':'NO'].join(','));
return [{json:{todayRows,headers,nowStr,today,allAbsent,noAbsencesToday:allAbsent.length===0}}];

// Handle both branches: true (Build Dashboard ran) or false (No Absences Today ran)
let built;
try { built = $('Build Dashboard and Report').first().json; } catch(e) {
  try { built = $('No Absences Today').first().json; } catch(e2) {
    const now2 = new Date(new Date().toLocaleString('en-US',{timeZone:'Asia/Kolkata'}));
    const dd2=String(now2.getDate()).padStart(2,'0'), mm2=String(now2.getMonth()+1).padStart(2,'0'), yyyy2=now2.getFullYear();
    built={todayRows:[],headers:'Date,StudentID,Name,Class,Subject,Teacher,Status,AbsencesLast30Days,ConsecutiveStreak,AttendancePct,Trend,AlertLevel,AlertReason,ParentName,EmailSent,WhatsAppSent',nowStr:now2.toLocaleString('en-IN',{timeZone:'Asia/Kolkata'}),today:`${dd2}-${mm2}-${yyyy2}`,allAbsent:[],noAbsencesToday:true};
  }
}
const {todayRows,headers,nowStr,today}=built;

// History comes as plain JSON rows from Extract History CSV3 (spreadsheetFile node)
const historyRows=$input.all().map(i=>i.json).filter(r=>r.Date&&r.StudentID&&r.AlertLevel);
const historical=historyRows.filter(r=>String(r.Date).trim()!==today);

// Parse today CSV lines into objects
function parseCSVLine(line){
  const res=[];let cur='',inQ=false;
  for(const c of line){if(c==='"'){inQ=!inQ;}else if(c===','&&!inQ){res.push(cur);cur='';}else cur+=c;}
  res.push(cur);return res.map(v=>v.trim().replace(/^"|"$/g,''));
}
const hdrArr=parseCSVLine(headers);
// If no absences today, show a clean "All Present" message in Today tab
const noAbsencesToday = built.noAbsencesToday === true;
const todayObjs=todayRows.map(line=>{const v=parseCSVLine(line);const o={};hdrArr.forEach((h,i)=>o[h]=v[i]||'');return o;});

const allData=[...historical,...todayObjs];

function toLine(r){
  const reason=(r.AlertReason||'').includes(',')?`"${r.AlertReason}"`:r.AlertReason||'';
  return [r.Date,r.StudentID,r.Name,r.Class,r.Subject,r.Teacher,r.Status,r.AbsencesLast30Days,r.ConsecutiveStreak,r.AttendancePct,r.Trend,r.AlertLevel,reason,r.ParentName,r.EmailSent,r.WhatsAppSent].join(',');
}
const fullCsv=[headers,...allData.map(toLine)].join('\n');

function parseDDMMYYYY(s){const p=String(s).split('-');return p.length===3?new Date(+p[2],+p[1]-1,+p[0]):new Date(0);}
function fmtMonth(s){const d=parseDDMMYYYY(s);return d.toLocaleString('en-IN',{month:'short',year:'numeric'});}
function getWeekKey(s){const d=parseDDMMYYYY(s);const day=d.getDay()||7;d.setDate(d.getDate()-day+1);return String(d.getDate()).padStart(2,'0')+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+d.getFullYear();}

const allDates=[...new Set(allData.map(r=>r.Date))].sort((a,b)=>parseDDMMYYYY(a)-parseDDMMYYYY(b));
const allMonths=[...new Set(allDates.map(fmtMonth))];
const allWeeks=[...new Set(allDates.map(getWeekKey))].sort((a,b)=>parseDDMMYYYY(a)-parseDDMMYYYY(b));
const classes=[...new Set(allData.map(r=>r.Class))].filter(Boolean).sort();
const subjects=[...new Set(allData.map(r=>r.Subject))].filter(Boolean).sort();
const students=[...new Set(allData.map(r=>r.StudentID))].filter(Boolean);

// ── Precompute per-student total days present/absent across all history ──
const studentStats={};
for(const sid of students){
  const rows=allData.filter(r=>r.StudentID===sid);
  const absent=rows.filter(r=>r.Status==='Absent').length;
  const name=rows[0].Name||sid;
