  const lastStreak=parseInt(rows[0].ConsecutiveStreak)||0;
  const lastPct=parseFloat(rows[0].AttendancePct)||100;
  studentStats[sid]={name,cls,absent,total:rows.length,lastAlert,lastTrend,lastAbs30,lastStreak,lastPct};
}

