      <div class="card"><h3>🟡 Medium Risk Students<\/h3><div class="scroll"><table class="tbl" id="medRiskTbl"><\/table><\/div><\/div>
    <\/div>
    <div class="g2">
      <div class="card"><h3>📈 Worsening Trend Students<\/h3><div class="scroll"><table class="tbl" id="worsenTbl"><\/table><\/div><\/div>
      <div class="card"><h3>Top 10 Most Absent (All Time)<\/h3><div id="topAbsentBar"><\/div><\/div>
    <\/div>
    <div class="card"><h3>Subject-wise At-Risk Distribution<\/h3><canvas id="riskSubjectChart" height="120"><\/canvas><\/div>
  <\/div>
<\/div>

<script>
const ALL_DATA=${JSON.stringify(allData)};
const ALL_NO_ABSENCES_TODAY=${JSON.stringify(noAbsencesToday)};
const ALL_DATES=${JSON.stringify(allDates)};
const ALL_MONTHS=${JSON.stringify(allMonths)};
const ALL_WEEKS=${JSON.stringify(allWeeks)};
const ALL_CLASSES=${JSON.stringify(classes)};
const ALL_SUBJECTS=${JSON.stringify(subjects)};
const STUDENT_STATS=${JSON.stringify(studentStats)};
const TODAY='${today}';

let charts={};
function parseDDMMYYYY(s){const p=String(s).split('-');return p.length===3?new Date(+p[2],+p[1]-1,+p[0]):new Date(0);}
function fmtMonth(s){return parseDDMMYYYY(s).toLocaleString('en-IN',{month:'short',year:'numeric'});}
function getWeekKey(s){const d=parseDDMMYYYY(s);const day=d.getDay()||7;d.setDate(d.getDate()-day+1);return String(d.getDate()).padStart(2,'0')+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+d.getFullYear();}
function dc(id){if(charts[id]){charts[id].destroy();delete charts[id];}}
function pct(a,t){return t===0?0:Math.round(a/t*100);}

// Global filters
function getFilters(){
  return {
    cls:document.getElementById('fClass').value,
    alert:document.getElementById('fAlert').value,
    trend:document.getElementById('fTrend').value
  };
}
function applyGlobalFilter(rows){
  const f=getFilters();
  return rows.filter(r=>(f.cls==='all'||r.Class===f.cls)&&(f.alert==='all'||r.AlertLevel===f.alert)&&(f.trend==='all'||r.Trend===f.trend));
}

function makeBar(id,items,cf,showPct){
  const el=document.getElementById(id);if(!el)return;
  if(!items.length){el.innerHTML='<div class="empty">No data<\/div>';return;}
  const mx=Math.max(...items.map(i=>i.val),1);
  el.innerHTML=items.slice(0,10).map(i=>'<div class="bar-row"><span class="bn" title="'+i.label+'">'+i.label+'<\/span><div class="bar-wrap"><div class="bar-fill" style="width:'+pct(i.val,mx)+'%;background:'+cf(i)+'"><\/div><\/div><span class="bv">'+(showPct?i.val+'%':i.val)+'<\/span><\/div>').join('');
}
function donut(id,labels,vals,colors){
  dc(id);const ctx=document.getElementById(id);if(!ctx)return;
  charts[id]=new Chart(ctx,{type:'doughnut',data:{labels,datasets:[{data:vals,backgroundColor:colors,borderWidth:0,hoverOffset:4}]},options:{responsive:true,plugins:{legend:{position:'bottom',labels:{font:{size:11},padding:8}}},cutout:'62%'}});
}
function lineChart(id,labels,datasets,opts){
  dc(id);const ctx=document.getElementById(id);if(!ctx)return;
  charts[id]=new Chart(ctx,{type:'line',data:{labels,datasets},options:{responsive:true,interaction:{mode:'index',intersect:false},scales:{x:{grid:{color:'#f1f5f9'},ticks:{font:{size:10},maxTicksLimit:12}},y:{beginAtZero:true,grid:{color:'#f1f5f9'},ticks:{font:{size:10}}},...(opts||{})},...(opts||{}),plugins:{legend:{labels:{font:{size:11}}}}}});
}
function barChart(id,labels,datasets){
  dc(id);const ctx=document.getElementById(id);if(!ctx)return;
  charts[id]=new Chart(ctx,{type:'bar',data:{labels,datasets},options:{responsive:true,scales:{x:{grid:{display:false},ticks:{font:{size:10}}},y:{beginAtZero:true,grid:{color:'#f1f5f9'},ticks:{font:{size:10}}}},plugins:{legend:{labels:{font:{size:11}}}}}});
}

function tblHTML(cols,rows){
  if(!rows.length)return '<tr><td class="empty" colspan="'+cols.length+'">No data<\/td><\/tr>';
  return '<thead><tr>'+cols.map(c=>'<th>'+c+'<\/th>').join('')+'<\/tr><\/thead><tbody>'+rows.join('')+'<\/tbody>';
}
function alertBadge(l){return '<span class="badge '+(l==='HIGH'?'b-high':l==='MEDIUM'?'b-med':'b-low')+'">'+l+'<\/span>';}
function trendBadge(t){return '<span class="badge '+(t==='WORSENING'?'b-w':t==='IMPROVING'?'b-i':'b-s')+'">'+t+'<\/span>';}
function pctColor(p){return +p>=85?'#16a34a':+p>=70?'#d97706':'#dc2626';}

// ── TODAY ──
function renderToday(){
  if(ALL_NO_ABSENCES_TODAY){
    document.getElementById('todayKpis').innerHTML='<div class="kpi" style="grid-column:1/-1;text-align:center;background:linear-gradient(135deg,#f0fdf4,#dcfce7);border:1px solid #bbf7d0"><div class="val" style="color:#16a34a;font-size:48px">✅</div><div class="lbl" style="font-size:16px;color:#16a34a;margin-top:8px">No Absences Today</div><div class="sub" style="color:#16a34a">All students were present on '+TODAY+'</div></div>';
    document.getElementById('todayClassBar').innerHTML='';
    document.getElementById('todaySubjectBar').innerHTML='';
    const tbl=document.getElementById('todayTbl');if(tbl)tbl.innerHTML='<tr><td class="empty" colspan="10" style="padding:40px;color:#16a34a;font-size:14px">✅ All students were present today — no absence records.</td></tr>';
    return;
  }
  const raw=ALL_DATA.filter(r=>r.Date===TODAY);
  const data=applyGlobalFilter(raw);
  const tot=data.length,high=data.filter(r=>r.AlertLevel==='HIGH').length,med=data.filter(r=>r.AlertLevel==='MEDIUM').length;
  const wors=data.filter(r=>r.Trend==='WORSENING').length,sent=data.filter(r=>r.EmailSent==='YES').length;
  const avgP=tot>0?Math.round(data.reduce((s,r)=>s+parseFloat(r.AttendancePct||0),0)/tot):0;
  document.getElementById('todayKpis').innerHTML=kpiHTML([
    {val:tot,lbl:'Absent Today',sub:TODAY,subc:'#64748b'},
    {val:high,lbl:'High Risk',sub:med+' medium',subc:'#d97706',vc:'#dc2626'},
    {val:wors,lbl:'Worsening',sub:data.filter(r=>r.Trend==='IMPROVING').length+' improving',subc:'#16a34a',vc:'#d97706'},
    {val:avgP+'%',lbl:'Avg Attendance',sub:avgP>=85?'On target':'Below 85%',subc:avgP>=85?'#16a34a':'#dc2626'},
    {val:sent,lbl:'Notified',sub:data.filter(r=>r.WhatsAppSent==='YES').length+' WhatsApp',subc:'#64748b',vc:'#16a34a'}
  ]);
  makeBar('todayClassBar',ALL_CLASSES.map(c=>({label:c,val:data.filter(r=>r.Class===c).length})),i=>i.val>5?'#ef4444':i.val>2?'#f59e0b':'#22c55e');
  makeBar('todaySubjectBar',ALL_SUBJECTS.map(s=>({label:s,val:data.filter(r=>r.Subject===s).length})).sort((a,b)=>b.val-a.val),()=>'#6366f1');
  const tbl=document.getElementById('todayTbl');
  if(tbl)tbl.innerHTML=tblHTML(['Student','Name','Class','Subject','Teacher','Abs 30d','Streak','Rate','Trend','Alert'],
    data.map(r=>'<tr><td>'+r.StudentID+'<\/td><td>'+(r.Name||'—')+'<\/td><td>'+r.Class+'<\/td><td>'+(r.Subject||'—')+'<\/td><td>'+(r.Teacher||'—')+'<\/td><td>'+r.AbsencesLast30Days+'<\/td><td>'+(+r.ConsecutiveStreak>0?'<b style="color:#dc2626">'+r.ConsecutiveStreak+'d<\/b>':'—')+'<\/td><td><span style="color:'+pctColor(r.AttendancePct)+'">'+parseFloat(r.AttendancePct).toFixed(1)+'%<\/span><\/td><td>'+trendBadge(r.Trend)+'<\/td><td>'+alertBadge(r.AlertLevel)+'<\/td><\/tr>'));
}

// ── WEEKLY ──
function renderWeekly(){
  const selWeek=document.getElementById('fWeek')&&document.getElementById('fWeek').value;
  const weekDates=selWeek&&selWeek!=='all'?ALL_DATES.filter(d=>getWeekKey(d)===selWeek):ALL_DATES.slice(-7);
  const raw=applyGlobalFilter(ALL_DATA.filter(r=>weekDates.includes(r.Date)));
  const tot=raw.length,high=raw.filter(r=>r.AlertLevel==='HIGH').length,med=raw.filter(r=>r.AlertLevel==='MEDIUM').length;
  const wors=raw.filter(r=>r.Trend==='WORSENING').length;
  const days=[...new Set(raw.map(r=>r.Date))].sort((a,b)=>parseDDMMYYYY(a)-parseDDMMYYYY(b));
  document.getElementById('weeklyKpis').innerHTML=kpiHTML([
    {val:tot,lbl:'Total Absences',sub:days.length+' school day(s)',subc:'#64748b'},
    {val:high,lbl:'High Risk',sub:med+' medium',subc:'#d97706',vc:'#dc2626'},
    {val:wors,lbl:'Worsening',sub:'trend',subc:'#64748b',vc:'#d97706'},
    {val:tot>0?Math.round(tot/Math.max(days.length,1)):0,lbl:'Avg/Day',sub:'absences',subc:'#64748b'},
    {val:[...new Set(raw.map(r=>r.StudentID))].length,lbl:'Unique Students',sub:'absent this week',subc:'#64748b'}
  ]);
  lineChart('weeklyDailyChart',days.map(d=>d.slice(0,5)),[
    {label:'Absences',data:days.map(d=>raw.filter(r=>r.Date===d).length),borderColor:'#6366f1',backgroundColor:'rgba(99,102,241,0.1)',tension:.3,fill:true,pointRadius:4}
  ]);
  makeBar('weeklySubjectBar',ALL_SUBJECTS.map(s=>({label:s,val:raw.filter(r=>r.Subject===s).length})).sort((a,b)=>b.val-a.val),()=>'#6366f1');
  // Top students this week by absence count
  const sidCounts={};raw.forEach(r=>{sidCounts[r.StudentID]=(sidCounts[r.StudentID]||0)+1;});
  const topRows=Object.entries(sidCounts).sort((a,b)=>b[1]-a[1]).slice(0,10);
  const wTbl=document.getElementById('weeklyTopTbl');
  if(wTbl)wTbl.innerHTML=tblHTML(['Student','Name','Class','Absences','Alert'],
    topRows.map(([sid,cnt])=>{const st=STUDENT_STATS[sid]||{};return '<tr><td>'+sid+'<\/td><td>'+(st.name||'—')+'<\/td><td>'+(st.cls||'—')+'<\/td><td><b>'+cnt+'<\/b><\/td><td>'+alertBadge(st.lastAlert||'LOW')+'<\/td><\/tr>';}));
  donut('weeklyAlertDonut',['High','Medium','Low'],[high,med,raw.filter(r=>r.AlertLevel==='LOW').length],['#ef4444','#f59e0b','#22c55e']);
}

// ── MONTHLY ──
function renderMonthly(){
  const selMonth=document.getElementById('fMonth')&&document.getElementById('fMonth').value;
  const curMonth=selMonth&&selMonth!=='all'?selMonth:(ALL_MONTHS[ALL_MONTHS.length-1]||'');
  const monthData=applyGlobalFilter(ALL_DATA.filter(r=>fmtMonth(r.Date)===curMonth));
  const tot=monthData.length,high=monthData.filter(r=>r.AlertLevel==='HIGH').length,med=monthData.filter(r=>r.AlertLevel==='MEDIUM').length;
  const wors=monthData.filter(r=>r.Trend==='WORSENING').length;
  const mDays=[...new Set(monthData.map(r=>r.Date))].sort((a,b)=>parseDDMMYYYY(a)-parseDDMMYYYY(b));
  const avgP=tot>0?Math.round(monthData.reduce((s,r)=>s+parseFloat(r.AttendancePct||0),0)/tot):0;
  document.getElementById('monthlyKpis').innerHTML=kpiHTML([
    {val:tot,lbl:'Total Absences',sub:curMonth,subc:'#64748b'},
    {val:high,lbl:'High Risk',sub:med+' medium',subc:'#d97706',vc:'#dc2626'},
    {val:wors,lbl:'Worsening',sub:'trend this month',subc:'#64748b',vc:'#d97706'},
    {val:avgP+'%',lbl:'Avg Attendance',sub:avgP>=85?'On target':'Below 85%',subc:avgP>=85?'#16a34a':'#dc2626'},
    {val:mDays.length,lbl:'School Days',sub:'recorded this month',subc:'#64748b'}
  ]);
  // Monthly trend over all months
  lineChart('monthlyTrendChart',ALL_MONTHS,[
    {label:'Total Absences',data:ALL_MONTHS.map(m=>ALL_DATA.filter(r=>fmtMonth(r.Date)===m).length),borderColor:'#6366f1',backgroundColor:'rgba(99,102,241,0.08)',tension:.3,fill:true,pointRadius:4,pointBackgroundColor:'#6366f1'},
    {label:'High Risk',data:ALL_MONTHS.map(m=>ALL_DATA.filter(r=>fmtMonth(r.Date)===m&&r.AlertLevel==='HIGH').length),borderColor:'#ef4444',backgroundColor:'transparent',tension:.3,pointRadius:3}
  ]);
  makeBar('monthlySubjectBar',ALL_SUBJECTS.map(s=>({label:s,val:monthData.filter(r=>r.Subject===s).length})).sort((a,b)=>b.val-a.val),()=>'#6366f1');
  // Top students this month
  const mSid={};monthData.forEach(r=>{mSid[r.StudentID]=(mSid[r.StudentID]||0)+1;});
  const mTop=Object.entries(mSid).sort((a,b)=>b[1]-a[1]).slice(0,10);
  const mTbl=document.getElementById('monthlyTopTbl');
  if(mTbl)mTbl.innerHTML=tblHTML(['Student','Name','Class','Absences','Alert'],
    mTop.map(([sid,cnt])=>{const st=STUDENT_STATS[sid]||{};return '<tr><td>'+sid+'<\/td><td>'+(st.name||'—')+'<\/td><td>'+(st.cls||'—')+'<\/td><td><b>'+cnt+'<\/b><\/td><td>'+alertBadge(st.lastAlert||'LOW')+'<\/td><\/tr>';}));
  // Class attendance % bar chart this month
  barChart('monthlyClassChart',ALL_CLASSES,[
    {label:'Avg Attendance %',data:ALL_CLASSES.map(c=>{const rows=monthData.filter(r=>r.Class===c);return rows.length?Math.round(rows.reduce((s,r)=>s+parseFloat(r.AttendancePct||0),0)/rows.length):0;}),backgroundColor:['#6366f1','#8b5cf6','#06b6d4','#10b981','#f59e0b'],borderRadius:6}
  ]);
  // Month summary cards
  const grid=document.getElementById('monthSummaryGrid');
  if(grid)grid.innerHTML=ALL_MONTHS.map(m=>{
    const rows=ALL_DATA.filter(r=>fmtMonth(r.Date)===m);
    const abs=rows.length,h=rows.filter(r=>r.AlertLevel==='HIGH').length,w=rows.filter(r=>r.Trend==='WORSENING').length;
    const ap=rows.length?Math.round(rows.reduce((s,r)=>s+parseFloat(r.AttendancePct||0),0)/rows.length):0;
    return '<div class="month-card"><h4>'+m+'<\/h4><div class="month-stat"><span>Total Absences<\/span><span>'+abs+'<\/span><\/div><div class="month-stat"><span>High Risk<\/span><span style="color:#dc2626">'+h+'<\/span><\/div><div class="month-stat"><span>Worsening<\/span><span style="color:#d97706">'+w+'<\/span><\/div><div class="month-stat"><span>Avg Attendance<\/span><span style="color:'+pctColor(ap)+'">'+ap+'%<\/span><\/div><\/div>';
  }).join('');
}

// ── FULL HISTORY ──
function renderHistory(){
  const fDate=document.getElementById('fDate')&&document.getElementById('fDate').value;
  const raw=fDate&&fDate!=='all'?ALL_DATA.filter(r=>r.Date===fDate):ALL_DATA;
  const data=applyGlobalFilter(raw);
  const tot=data.length,high=data.filter(r=>r.AlertLevel==='HIGH').length;
  const wors=data.filter(r=>r.Trend==='WORSENING').length;
  const avgP=tot>0?Math.round(data.reduce((s,r)=>s+parseFloat(r.AttendancePct||0),0)/tot):0;
  document.getElementById('histKpis').innerHTML=kpiHTML([
    {val:tot,lbl:'Total Records',sub:[...new Set(data.map(r=>r.Date))].length+' day(s)',subc:'#64748b'},
    {val:high,lbl:'High Risk',sub:data.filter(r=>r.AlertLevel==='MEDIUM').length+' medium',subc:'#d97706',vc:'#dc2626'},
    {val:wors,lbl:'Worsening',sub:data.filter(r=>r.Trend==='IMPROVING').length+' improving',subc:'#16a34a',vc:'#d97706'},
    {val:avgP+'%',lbl:'Avg Attendance',sub:avgP>=85?'On target':'Below 85%',subc:avgP>=85?'#16a34a':'#dc2626'},
    {val:ALL_MONTHS.length,lbl:'Months Tracked',sub:ALL_DATES.length+' total days',subc:'#64748b'}
  ]);
  lineChart('histDailyChart',ALL_DATES.map(d=>d.slice(0,5)),[
    {label:'High',data:ALL_DATES.map(d=>ALL_DATA.filter(r=>r.Date===d&&r.AlertLevel==='HIGH').length),borderColor:'#ef4444',backgroundColor:'rgba(239,68,68,0.08)',tension:.3,fill:true,pointRadius:2},
    {label:'Medium',data:ALL_DATES.map(d=>ALL_DATA.filter(r=>r.Date===d&&r.AlertLevel==='MEDIUM').length),borderColor:'#f59e0b',backgroundColor:'rgba(245,158,11,0.08)',tension:.3,fill:true,pointRadius:2},
    {label:'Low',data:ALL_DATES.map(d=>ALL_DATA.filter(r=>r.Date===d&&r.AlertLevel==='LOW').length),borderColor:'#22c55e',backgroundColor:'rgba(34,197,94,0.06)',tension:.3,fill:true,pointRadius:2}
  ]);
  lineChart('histClassChart',ALL_DATES.map(d=>d.slice(0,5)),ALL_CLASSES.map((c,i)=>({
    label:c,
    data:ALL_DATES.map(d=>{const rows=ALL_DATA.filter(r=>r.Date===d&&r.Class===c);return rows.length?Math.round(rows.reduce((s,r)=>s+parseFloat(r.AttendancePct||0),0)/rows.length):null;}),
    borderColor:['#6366f1','#8b5cf6','#06b6d4','#10b981','#f59e0b'][i%5],
    backgroundColor:'transparent',tension:.3,pointRadius:1,spanGaps:true
  })));
  makeBar('histSubjectBar',ALL_SUBJECTS.map(s=>({label:s,val:data.filter(r=>r.Subject===s).length})).sort((a,b)=>b.val-a.val),()=>'#6366f1');
  barChart('histAlertChart',ALL_MONTHS,[
    {label:'High',data:ALL_MONTHS.map(m=>ALL_DATA.filter(r=>fmtMonth(r.Date)===m&&r.AlertLevel==='HIGH').length),backgroundColor:'#ef4444',borderRadius:4},
    {label:'Medium',data:ALL_MONTHS.map(m=>ALL_DATA.filter(r=>fmtMonth(r.Date)===m&&r.AlertLevel==='MEDIUM').length),backgroundColor:'#f59e0b',borderRadius:4},
    {label:'Low',data:ALL_MONTHS.map(m=>ALL_DATA.filter(r=>fmtMonth(r.Date)===m&&r.AlertLevel==='LOW').length),backgroundColor:'#22c55e',borderRadius:4}
  ]);
  const hTbl=document.getElementById('histTbl');
  if(hTbl)hTbl.innerHTML=tblHTML(['Date','Student','Name','Class','Subject','Abs 30d','Rate','Trend','Alert'],
    data.sort((a,b)=>parseDDMMYYYY(b.Date)-parseDDMMYYYY(a.Date)).map(r=>'<tr><td>'+r.Date+'<\/td><td>'+r.StudentID+'<\/td><td>'+(r.Name||'—')+'<\/td><td>'+r.Class+'<\/td><td>'+(r.Subject||'—')+'<\/td><td>'+r.AbsencesLast30Days+'<\/td><td><span style="color:'+pctColor(r.AttendancePct)+'">'+parseFloat(r.AttendancePct).toFixed(1)+'%<\/span><\/td><td>'+trendBadge(r.Trend)+'<\/td><td>'+alertBadge(r.AlertLevel)+'<\/td><\/tr>'));
}

// ── AT-RISK ──
function renderRisk(){
  const data=applyGlobalFilter(ALL_DATA);
  // Use latest record per student
  const latestBySid={};
  data.forEach(r=>{if(!latestBySid[r.StudentID]||parseDDMMYYYY(r.Date)>parseDDMMYYYY(latestBySid[r.StudentID].Date))latestBySid[r.StudentID]=r;});
  const latest=Object.values(latestBySid);
  const high=latest.filter(r=>r.AlertLevel==='HIGH'),med=latest.filter(r=>r.AlertLevel==='MEDIUM');
  const wors=latest.filter(r=>r.Trend==='WORSENING');
  document.getElementById('riskKpis').innerHTML=kpiHTML([
    {val:high.length,lbl:'High Risk Students',sub:'5+ abs or 3 consecutive',subc:'#64748b',vc:'#dc2626'},
    {val:med.length,lbl:'Medium Risk',sub:'3–4 absences in 30d',subc:'#64748b',vc:'#d97706'},
    {val:wors.length,lbl:'Worsening Trend',sub:'recent pattern up',subc:'#64748b',vc:'#d97706'},
    {val:latest.filter(r=>+r.ConsecutiveStreak>=3).length,lbl:'3+ Day Streak',sub:'consecutive absences',subc:'#64748b',vc:'#dc2626'},
    {val:latest.filter(r=>parseFloat(r.AttendancePct)<75).length,lbl:'Below 75%',sub:'attendance rate',subc:'#64748b',vc:'#dc2626'}
  ]);
  const rCols=['Student','Name','Class','Last Absent','Abs 30d','Streak','Rate','Trend'];
  const rRow=r=>'<tr><td>'+r.StudentID+'<\/td><td>'+(r.Name||'—')+'<\/td><td>'+r.Class+'<\/td><td>'+r.Date+'<\/td><td><b style="color:#dc2626">'+r.AbsencesLast30Days+'<\/b><\/td><td>'+(+r.ConsecutiveStreak>0?'<b style="color:#dc2626">'+r.ConsecutiveStreak+'d<\/b>':'—')+'<\/td><td><span style="color:'+pctColor(r.AttendancePct)+'">'+parseFloat(r.AttendancePct).toFixed(1)+'%<\/span><\/td><td>'+trendBadge(r.Trend)+'<\/td><\/tr>';
  const hTbl=document.getElementById('highRiskTbl');if(hTbl)hTbl.innerHTML=tblHTML(rCols,high.sort((a,b)=>+b.AbsencesLast30Days-+a.AbsencesLast30Days).map(rRow));
  const mTbl=document.getElementById('medRiskTbl');if(mTbl)mTbl.innerHTML=tblHTML(rCols,med.sort((a,b)=>+b.AbsencesLast30Days-+a.AbsencesLast30Days).map(rRow));
  const wTbl=document.getElementById('worsenTbl');if(wTbl)wTbl.innerHTML=tblHTML(rCols,wors.sort((a,b)=>+b.AbsencesLast30Days-+a.AbsencesLast30Days).map(rRow));
  // Top 10 most absent all time
  const topAbs=Object.entries(STUDENT_STATS).sort((a,b)=>b[1].absent-a[1].absent).slice(0,10);
  makeBar('topAbsentBar',topAbs.map(([sid,s])=>({label:s.name||sid,val:s.absent})),i=>{const r=i.val/Math.max(...topAbs.map(x=>x[1].absent),1);return r>0.7?'#ef4444':r>0.4?'#f59e0b':'#6366f1';});
  // Subject risk chart
  barChart('riskSubjectChart',ALL_SUBJECTS,[
    {label:'High Risk',data:ALL_SUBJECTS.map(s=>high.filter(r=>r.Subject===s).length),backgroundColor:'#ef4444',borderRadius:4},
    {label:'Medium Risk',data:ALL_SUBJECTS.map(s=>med.filter(r=>r.Subject===s).length),backgroundColor:'#f59e0b',borderRadius:4}
  ]);
}

function kpiHTML(items){
  return items.map(({val,lbl,sub,subc,vc})=>'<div class="kpi"><div class="val"'+(vc?' style="color:'+vc+'"':'')+'>'+(val??0)+'<\/div><div class="lbl">'+lbl+'<\/div>'+(sub?'<div class="sub" style="color:'+(subc||'#64748b')+'">'+sub+'<\/div>':'')+'<\/div>').join('');
}

function applyFilters(){
  const active=document.querySelector('.tab.active');
  if(active)active.click();
}

function switchTab(id,el){
  document.querySelectorAll('.section').forEach(s=>s.classList.remove('active'));
  document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  el.classList.add('active');
  setTimeout(()=>{
    if(id==='today')renderToday();
    else if(id==='weekly')renderWeekly();
    else if(id==='monthly')renderMonthly();
    else if(id==='history')renderHistory();
    else if(id==='risk')renderRisk();
  },30);
}

